import{_ as r,C as d,o as s,c as n,ag as i,E as c,j as e,a as o}from"./chunks/framework._658-eYr.js";const f=JSON.parse('{"title":"Jobs & Workers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/jobs.md","filePath":"guide/jobs.md"}'),l={name:"guide/jobs.md"};function p(h,t,u,b,g,m){const a=d("SchemeImage");return s(),n("div",null,[t[0]||(t[0]=i(`<h1 id="jobs-workers" tabindex="-1">Jobs &amp; Workers <a class="header-anchor" href="#jobs-workers" aria-label="Permalink to &quot;Jobs &amp; Workers&quot;">​</a></h1><p>CRAFT uses NATS JetStream for distributed async job processing. Long-running tasks (AI generation, video rendering, pipeline orchestration) run as background workers with real-time status updates via SSE. Jobs are <strong>channel-scoped</strong> and available to <strong>premium users</strong> only.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Frontend ──SSE──&gt; Express API ──NATS──&gt; Worker Pool</span></span>
<span class="line"><span>                       ↑                    │</span></span>
<span class="line"><span>                  Job Manager          Process &amp; Ack</span></span>
<span class="line"><span>                       ↑                    │</span></span>
<span class="line"><span>                  Redis Cache        Result / Error</span></span></code></pre></div><p>Jobs appear <strong>under channels</strong> in the sidebar (not as a standalone section). Use the <code>?channelId=</code> query parameter on <code>GET /api/jobs</code> to filter jobs by channel.</p><h2 id="workers" tabindex="-1">Workers <a class="header-anchor" href="#workers" aria-label="Permalink to &quot;Workers&quot;">​</a></h2><p>All Claude-using workers run as the <code>studio</code> user (not root) to support the Agent SDK. NATS consumers use wildcard subjects for user-scoped routing (e.g., <code>pipeline.jobs.{username}.&gt;</code>).</p><table tabindex="0"><thead><tr><th>Worker</th><th>Task</th><th>Memory</th><th>Concurrency</th></tr></thead><tbody><tr><td><code>worker-orchestrate</code></td><td>8-stage pipeline orchestration with quality gates</td><td>4G</td><td>1 (sequential)</td></tr><tr><td><code>worker-idea</code></td><td>AI idea generation</td><td>2G</td><td>2</td></tr><tr><td><code>worker-tts</code></td><td>Text-to-speech rendering + merge</td><td>1G</td><td>2</td></tr><tr><td><code>worker-discover</code></td><td>YouTube yt-dlp discovery</td><td>2G</td><td>2</td></tr><tr><td><code>worker-proposals</code></td><td>AI proposal generation and scoring</td><td>2G</td><td>2</td></tr><tr><td><code>worker-fact-check</code></td><td>Content fact-checking</td><td>2G</td><td>2</td></tr><tr><td><code>worker-humanize</code></td><td>Text humanization</td><td>2G</td><td>2</td></tr><tr><td><code>worker-resource-download</code></td><td>Asset downloading</td><td>1G</td><td>3</td></tr><tr><td><code>worker-render</code></td><td>Remotion MP4 export (Chromium)</td><td>8G</td><td>1</td></tr></tbody></table><h2 id="job-lifecycle" tabindex="-1">Job Lifecycle <a class="header-anchor" href="#job-lifecycle" aria-label="Permalink to &quot;Job Lifecycle&quot;">​</a></h2><ol><li><strong>Queued</strong> — job submitted via API, published to NATS JetStream</li><li><strong>Running</strong> — worker picks up the job, sends progress updates via <code>publishOutput()</code></li><li><strong>Completed</strong> — worker acks the message, SSE event fired to frontend</li><li><strong>Failed</strong> — error captured, message nak&#39;d for retry (up to 3 attempts)</li></ol><h2 id="orchestration-jobs" tabindex="-1">Orchestration Jobs <a class="header-anchor" href="#orchestration-jobs" aria-label="Permalink to &quot;Orchestration Jobs&quot;">​</a></h2><p>The <code>worker-orchestrate</code> service is special — it coordinates multi-stage pipelines by:</p><ol><li>Loading the episode manifest to find the next pending stage</li><li>Invoking the appropriate AI agent via the Claude Agent SDK</li><li>Running the Producer agent for quality review</li><li>Writing feedback and iterating if the review fails</li><li>Advancing to the next stage or pausing for human intervention</li></ol><p>Orchestration jobs have a 1-hour ack timeout to accommodate long-running agent chains. The worker runs as the <code>studio</code> user (not root) to support the Agent SDK&#39;s <code>--dangerously-skip-permissions</code> flag.</p><h2 id="cancellation" tabindex="-1">Cancellation <a class="header-anchor" href="#cancellation" aria-label="Permalink to &quot;Cancellation&quot;">​</a></h2><p>Jobs can be cancelled via <code>POST /api/jobs/:id/cancel</code>. The orchestrate worker subscribes to its cancel subject and checks between stages — a cancelled pipeline stops cleanly at the next stage boundary.</p><h2 id="real-time-updates" tabindex="-1">Real-Time Updates <a class="header-anchor" href="#real-time-updates" aria-label="Permalink to &quot;Real-Time Updates&quot;">​</a></h2><p>The SSE bridge subscribes to <code>pipeline.&gt;</code> on NATS and translates events for the frontend:</p><table tabindex="0"><thead><tr><th>NATS Subject</th><th>SSE Event</th></tr></thead><tbody><tr><td><code>pipeline.job.status.*</code></td><td><code>job:status</code></td></tr><tr><td><code>pipeline.job.output.*</code></td><td><code>job:output</code></td></tr><tr><td><code>pipeline.stage.updated.*</code></td><td><code>stage:updated</code></td></tr><tr><td><code>pipeline.state.proposals.*</code></td><td><code>proposals:updated</code></td></tr></tbody></table>`,19)),c(a,{name:"jobs-panel",alt:"Jobs Panel"}),t[1]||(t[1]=e("div",{class:"tip custom-block"},[e("p",{class:"custom-block-title"},"TIP"),e("p",null,[o("Start workers with "),e("code",null,"docker compose up -d"),o(" — they share the "),e("code",null,"craft-studio:latest"),o(" image and connect to NATS automatically.")])],-1))])}const S=r(l,[["render",p]]);export{f as __pageData,S as default};
